  1→// ── SessionHeader Preact component ───────────────────────────
  2→//
  3→// Replaces the imperative updateChatSessionHeader() with a reactive
  4→// Preact component reading sessionStore.activeSession.
  5→
  6→import { html } from "htm/preact";
  7→import { useCallback, useEffect, useRef, useState } from "preact/hooks";
  8→import { onEvent } from "../events.js";
  9→import * as gon from "../gon.js";
 10→import { parseAgentsListPayload, sendRpc } from "../helpers.js";
 11→import {
 12→	clearActiveSession,
 13→	fetchSessions,
 14→	setSessionActiveRunId,
 15→	setSessionReplying,
 16→	switchSession,
 17→} from "../sessions.js";
 18→import { sessionStore } from "../stores/session-store.js";
 19→import { ComboSelect, confirmDialog, shareLinkDialog, shareVisibilityDialog, showToast } from "../ui.js";
 20→
 21→function nextSessionKey(currentKey) {
 22→	var allSessions = sessionStore.sessions.value;
 23→	var s = allSessions.find((x) => x.key === currentKey);
 24→	if (s?.parentSessionKey) return s.parentSessionKey;
 25→	var idx = allSessions.findIndex((x) => x.key === currentKey);
 26→	if (idx >= 0 && idx + 1 < allSessions.length) return allSessions[idx + 1].key;
 27→	if (idx > 0) return allSessions[idx - 1].key;
 28→	return "main";
 29→}
 30→
 31→function buildShareUrl(payload) {
 32→	var url = `${window.location.origin}${payload.path}`;
 33→	if (payload.accessKey) {
 34→		url += `?k=${encodeURIComponent(payload.accessKey)}`;
 35→	}
 36→	return url;
 37→}
 38→
 39→function isSshTargetNode(node) {
 40→	return node?.platform === "ssh" || String(node?.nodeId || "").startsWith("ssh:");
 41→}
 42→
 43→function nodeOptionLabel(node) {
 44→	if (!node) return "Local";
 45→	if (node.displayName) return node.displayName;
 46→	if (isSshTargetNode(node)) {
 47→		var target = String(node.nodeId || "").replace(/^ssh:/, "");
 48→		return `SSH: ${target}`;
 49→	}
 50→	return node.nodeId;
 51→}
 52→
 53→async function copyShareUrl(url, visibility) {
 54→	try {
 55→		if (navigator.clipboard?.writeText) {
 56→			await navigator.clipboard.writeText(url);
 57→			showToast("Share link copied", "success");
 58→			return;
 59→		}
 60→	} catch (_err) {
 61→		// Clipboard APIs can fail on some browsers/permissions.
 62→	}
 63→	await shareLinkDialog(url, visibility);
 64→}
 65→
 66→export function SessionHeader({
 67→	showSelectors = true,
 68→	showName = true,
 69→	showShare = true,
 70→	showFork = true,
 71→	showStop = true,
 72→	showClear = true,
 73→	showDelete = true,
 74→	nameOwnLine = false,
 75→	showRenameButton = false,
 76→	actionButtonClass = "chat-session-btn",
 77→	onBeforeShare = null,
 78→	onBeforeDelete = null,
 79→} = {}) {
 80→	var session = sessionStore.activeSession.value;
 81→	var currentKey = sessionStore.activeSessionKey.value;
 82→	var gonAgentsPayload = parseAgentsListPayload(gon.get("agents"));
 83→	var initialAgentOptions = Array.isArray(gonAgentsPayload?.agents) ? gonAgentsPayload.agents : [];
 84→	var initialDefaultAgentId = typeof gonAgentsPayload?.defaultId === "string" ? gonAgentsPayload.defaultId : "main";
 85→
 86→	var [renaming, setRenaming] = useState(false);
 87→	var [clearing, setClearing] = useState(false);
 88→	var [stopping, setStopping] = useState(false);
 89→	var [switchingAgent, setSwitchingAgent] = useState(false);
 90→	var [agentOptions, setAgentOptions] = useState(initialAgentOptions);
 91→	var [defaultAgentId, setDefaultAgentId] = useState(initialDefaultAgentId);
 92→	var [agentOptionsLoaded, setAgentOptionsLoaded] = useState(initialAgentOptions.length > 0);
 93→	var [nodeOptions, setNodeOptions] = useState([]);
 94→	var [switchingNode, setSwitchingNode] = useState(false);
 95→	var inputRef = useRef(null);
 96→
 97→	var fullName = session ? session.label || session.key : currentKey;
 98→	var displayName = nameOwnLine ? fullName : fullName.length > 20 ? `${fullName.slice(0, 20)}\u2026` : fullName;
 99→	var replying = session?.replying.value;
100→	var activeRunId = session?.activeRunId.value || null;
101→
102→	var isMain = currentKey === "main";
103→	var isChannel = session?.channelBinding || currentKey.startsWith("telegram:") || currentKey.startsWith("msteams:");
104→	var isCron = currentKey.startsWith("cron:");
105→	var canRename = !(isMain || isChannel || isCron);
106→	var canStop = !isCron && replying;
107→	var currentAgentId = session?.agent_id || defaultAgentId || "main";
108→	var currentNodeId = session?.node_id || "";
109→
110→	useEffect(() => {
111→		var cancelled = false;
112→		sendRpc("agents.list", {}).then((res) => {
113→			if (cancelled) return;
114→			if (!res?.ok) {
115→				setAgentOptionsLoaded(true);
116→				return;
117→			}
118→			var parsed = parseAgentsListPayload(res.payload);
119→			setDefaultAgentId(parsed.defaultId);
120→			setAgentOptions(parsed.agents);
121→			setAgentOptionsLoaded(true);
122→		});
123→		return () => {
124→			cancelled = true;
125→		};
126→	}, [currentKey]);
127→
128→	// Fetch connected nodes and subscribe to presence updates.
129→	useEffect(() => {
130→		var cancelled = false;
131→		var fetchNodes = () => {
132→			sendRpc("node.list", {}).then((res) => {
133→				if (cancelled || !res?.ok) return;
134→				setNodeOptions(Array.isArray(res.payload) ? res.payload : []);
135→			});
136→		};
137→		fetchNodes();
138→		var unsub = onEvent("presence", () => {
139→			if (!cancelled) fetchNodes();
140→		});
141→		return () => {
142→			cancelled = true;
143→			unsub();
144→		};
145→	}, [currentKey]);
146→
147→	var startRename = useCallback(() => {
148→		if (!canRename) return;
149→		setRenaming(true);
150→		requestAnimationFrame(() => {
151→			if (inputRef.current) {
152→				inputRef.current.value = fullName;
153→				inputRef.current.focus();
154→				inputRef.current.select();
155→			}
156→		});
157→	}, [canRename, fullName]);
158→
159→	var commitRename = useCallback(() => {
160→		var val = inputRef.current?.value.trim() || "";
161→		setRenaming(false);
162→		if (val && val !== fullName) {
163→			sendRpc("sessions.patch", { key: currentKey, label: val }).then((res) => {
164→				if (res?.ok) fetchSessions();
165→			});
166→		}
167→	}, [currentKey, fullName]);
168→
169→	var onKeyDown = useCallback(
170→		(e) => {
171→			if (e.key === "Enter" && !e.isComposing) {
172→				e.preventDefault();
173→				commitRename();
174→			}
175→			if (e.key === "Escape") {
176→				setRenaming(false);
177→			}
178→		},
179→		[commitRename],
180→	);
181→
182→	var onFork = useCallback(() => {
183→		sendRpc("sessions.fork", { key: currentKey }).then((res) => {
184→			if (res?.ok && res.payload?.sessionKey) {
185→				fetchSessions();
186→				switchSession(res.payload.sessionKey);
187→			}
188→		});
189→	}, [currentKey]);
190→
191→	var onDelete = useCallback(() => {
192→		if (typeof onBeforeDelete === "function") {
193→			onBeforeDelete();
194→		}
195→		var msgCount = session ? session.messageCount || 0 : 0;
196→		var nextKey = nextSessionKey(currentKey);
197→		var doDelete = () => {
198→			sendRpc("sessions.delete", { key: currentKey }).then((res) => {
199→				if (res && !res.ok && res.error && res.error.indexOf("uncommitted changes") !== -1) {
200→					confirmDialog("Worktree has uncommitted changes. Force delete?").then((yes) => {
201→						if (!yes) return;
202→						sendRpc("sessions.delete", { key: currentKey, force: true }).then(() => {
203→							switchSession(nextKey);
204→							fetchSessions();
205→						});
206→					});
207→					return;
208→				}
209→				switchSession(nextKey);
210→				fetchSessions();
211→			});
212→		};
213→		var isUnmodifiedFork = session && session.forkPoint != null && msgCount <= session.forkPoint;
214→		if (msgCount > 0 && !isUnmodifiedFork) {
215→			confirmDialog("Delete this session?").then((yes) => {
216→				if (yes) doDelete();
217→			});
218→		} else {
219→			doDelete();
220→		}
221→	}, [currentKey, onBeforeDelete, session]);
222→
223→	var onClear = useCallback(() => {
224→		if (clearing) return;
225→		setClearing(true);
226→		clearActiveSession().finally(() => {
227→			setClearing(false);
228→		});
229→	}, [clearing]);
230→
231→	var onStop = useCallback(() => {
232→		if (stopping) return;
233→		var params = { sessionKey: currentKey };
234→		if (activeRunId) params.runId = activeRunId;
235→		setStopping(true);
236→		sendRpc("chat.abort", params)
237→			.then((res) => {
238→				if (!res?.ok) {
239→					showToast(res?.error?.message || "Failed to stop response", "error");
240→					return;
241→				}
242→				setSessionActiveRunId(currentKey, null);
243→				setSessionReplying(currentKey, false);
244→			})
245→			.finally(() => {
246→				setStopping(false);
247→			});
248→	}, [activeRunId, currentKey, stopping]);
249→
250→	var shareSnapshot = useCallback(
251→		async (visibility) => {
252→			var res = await sendRpc("sessions.share.create", { key: currentKey, visibility: visibility });
253→			if (!(res?.ok && res.payload?.path)) {
254→				showToast(res?.error?.message || "Failed to create share link", "error");
255→				return;
256→			}
257→
258→			var url = buildShareUrl(res.payload);
259→			await copyShareUrl(url, visibility);
260→
261→			if (visibility === "private") {
262→				showToast("Private link includes a key, share it only with trusted people", "success");
263→			}
264→
265→			// Reload the active session so the snapshot cutoff notice appears.
266→			switchSession(currentKey);
267→			fetchSessions();
268→		},
269→		[currentKey],
270→	);
271→
272→	var onShare = useCallback(() => {
273→		if (typeof onBeforeShare === "function") {
274→			onBeforeShare();
275→		}
276→		shareVisibilityDialog().then((visibility) => {
277→			if (!visibility) return;
278→			void shareSnapshot(visibility);
279→		});
280→	}, [onBeforeShare, shareSnapshot]);
281→
282→	var onAgentChange = useCallback(
283→		(nextAgentId) => {
284→			if (!nextAgentId || nextAgentId === currentAgentId || switchingAgent) {
285→				return;
286→			}
287→			setSwitchingAgent(true);
288→			sendRpc("agents.set_session", {
289→				session_key: currentKey,
290→				agent_id: nextAgentId,
291→			})
292→				.then((res) => {
293→					if (!res?.ok) {
294→						showToast(res?.error?.message || "Failed to switch agent", "error");
295→						return;
296→					}
297→					if (session) {
298→						session.agent_id = nextAgentId;
299→						session.dataVersion.value++;
300→					}
301→					fetchSessions();
302→				})
303→				.finally(() => {
304→					setSwitchingAgent(false);
305→				});
306→		},
307→		[currentAgentId, currentKey, session, switchingAgent],
308→	);
309→
310→	var onNodeChange = useCallback(
311→		(nextNodeId) => {
312→			if (switchingNode) return;
313→			setSwitchingNode(true);
314→			sendRpc("nodes.set_session", {
315→				session_key: currentKey,
316→				node_id: nextNodeId || null,
317→			})
318→				.then((res) => {
319→					if (!res?.ok) {
320→						showToast(res?.error?.message || "Failed to switch node", "error");
321→						return;
322→					}
323→					if (session) {
324→						session.node_id = nextNodeId || null;
